document.getElementById('photoUploadStatus'); const imgEl = document.getElementById('employeePhotoImg');
// Client-side size check (5MB) if (file.size > 5 * 1024 * 1024) { statusEl.innerHTML = '


    File too large. Max 5MB.

'; return; } statusEl.innerHTML = '


